// ─────────────────────────────────────────────
// VHSYS :: nf_service_info
// Rota   : POST /nf_service_info
// Fase 5 : Fluxos NF
// ─────────────────────────────────────────────
// Input  : { data: { services: [{ chave_nf, detalhes... }] } }
// Output : { message: 'Service info updated successfully', services_info_updated: number } HTTP 201
// Banco  : UPSERT nf_service_info por chave_nf + enriquecimento com labels
// Chave  : chave_nf
// ─────────────────────────────────────────────

const body = $input.first().json.body || $input.first().json;

if (!body.data) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Missing required field: data' }
  };
}

if (!body.data.services || !Array.isArray(body.data.services)) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Missing or invalid services array' }
  };
}

const services = body.data.services;

if (services.length === 0) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Services array cannot be empty' }
  };
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_info',
  event: 'input_validated',
  services_count: services.length,
  level: 'info'
}));

return { _valid: true, services };

// Transform e normaliza dados das informações de serviço
// Expande cada serviço para um item separado
const ctx = $input.first().json;
const services = ctx.services;

// Decode HTML entities function (reutilizada)
function decodeHtml(obj) {
  if (typeof obj === 'string') {
    return obj
      .replace(/&amp;/g,  '&')
      .replace(/&lt;/g,   '<')
      .replace(/&gt;/g,   '>')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g,  "'")
      .replace(/&#x27;/g, "'")
      .replace(/&#x2F;/g, '/')
      .replace(/&nbsp;/g, ' ');
  }
  if (Array.isArray(obj)) return obj.map(decodeHtml);
  if (typeof obj === 'object' && obj !== null) {
    const out = {};
    for (const k in obj) out[k] = decodeHtml(obj[k]);
    return out;
  }
  return obj;
}

// Helper para converter valor
function parseValue(value) {
  if (!value) return 0;
  const cleaned = String(value).replace(/[^0-9.,]/g, '').replace(',', '.');
  const num = parseFloat(cleaned);
  return isNaN(num) ? 0 : num;
}

const decodedServices = decodeHtml(services);

const transformedServices = decodedServices.map((service, index) => {
  const chaveNf = String(service.chave_nf || service.ChaveNF || service.id || '').trim();

  if (!chaveNf) {
    console.log(JSON.stringify({
      timestamp: new Date().toISOString(),
      route: 'nf_service_info',
      event: 'service_skipped_no_chave',
      service_index: index,
      service_data: service,
      level: 'warn'
    }));
    return null;
  }

  return {
    chave_nf: chaveNf,
    codigo_servico: String(service.codigo_servico || service.CodigoServico || '').trim(),
    item_lista_servico: String(service.item_lista_servico || service.ItemListaServico || '').trim(),
    codigo_cnae: String(service.codigo_cnae || service.CodigoCNAE || '').trim(),
    codigo_tributacao_municipio: String(service.codigo_tributacao_municipio || service.CodigoTributacaoMunicipio || '').trim(),
    discriminacao_detalhada: String(service.discriminacao_detalhada || service.DiscriminacaoDetalhada || service.Discriminacao || '').trim(),
    quantidade: parseValue(service.quantidade || service.Quantidade || 1),
    valor_unitario: parseValue(service.valor_unitario || service.ValorUnitario || 0),
    valor_desconto: parseValue(service.valor_desconto || service.ValorDesconto || 0),
    valor_outras_retencoes: parseValue(service.valor_outras_retencoes || service.ValorOutrasRetencoes || 0),
    base_calculo_issqn: parseValue(service.base_calculo_issqn || service.BaseCalculoISSQN || 0),
    aliquota_issqn: parseValue(service.aliquota_issqn || service.AliquotaISSQN || 0),
    valor_issqn: parseValue(service.valor_issqn || service.ValorISSQN || 0),
    municipio_incidencia: String(service.municipio_incidencia || service.MunicipioIncidencia || '').trim(),
    numero_processo: String(service.numero_processo || service.NumeroProcesso || '').trim(),
    observacoes: String(service.observacoes || service.Observacoes || '').trim()
  };
}).filter(service => service !== null);

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_info',
  event: 'services_transformed',
  valid_services: transformedServices.length,
  total_input: decodedServices.length,
  level: 'info'
}));

return transformedServices;

// Combina dados do serviço com enriquecimento de labels
const enrichmentResults = $input.all();
const originalServices = $('Transform Service Info').all();

// Cria mapa de enriquecimento
const enrichmentMap = {};
enrichmentResults.forEach(result => {
  if (result.json && result.json.chave_nf) {
    enrichmentMap[result.json.chave_nf] = {
      label_descricao: result.json.label_descricao,
      label_aliquota_iss: result.json.label_aliquota_iss
    };
  }
});

// Aplica enriquecimento
const enrichedServices = originalServices.map(serviceItem => {
  const service = serviceItem.json;
  const enrichment = enrichmentMap[service.chave_nf] || {};

  return {
    ...service,
    label_descricao: enrichment.label_descricao || null,
    label_aliquota_iss: enrichment.label_aliquota_iss || null
  };
});

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_info',
  event: 'services_enriched',
  enriched_count: enrichedServices.filter(s => s.label_descricao).length,
  total_services: enrichedServices.length,
  level: 'info'
}));

return enrichedServices;

// Conta registros afetados e constrói resposta
const affectedRecords = $input.all()
  .filter(item => item.json && item.json.chave_nf)
  .length;

const enrichedCount = $input.all()
  .filter(item => item.json && item.json.label_descricao)
  .length;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_info',
  event: 'service_info_upserted',
  services_info_updated: affectedRecords,
  enriched_with_labels: enrichedCount,
  level: 'info'
}));

// statusCode 201 — preserva compatibilidade com Flask original
return {
  statusCode: 201,
  body: {
    message: 'Service info updated successfully',
    services_info_updated: affectedRecords,
    enriched_with_labels: enrichedCount
  }
};

// Erro de validação
const input = $input.first().json;
return {
  statusCode: input.statusCode || 400,
  body: input.body || { ok: false, error: 'Validation failed' }
};

// Erro de banco
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_info',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not update service info' }
};

// Return the response data as-is
const response = $input.first().json;
return response;
